INSERT INTO domain_member_role (domain_member_id, domain_role_id, created_at)
SELECT #{memberId}, #{roleId}, CURRENT_TIMESTAMP(3)
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM domain_member_role
    WHERE domain_member_id = #{memberId}
      AND domain_role_id = #{roleId}
)

